Tenho esse Listener que ficou gigante, com toda a lógica dentro do afterInsert. Preciso refatorar:

```java
public class PedidoListener extends PersistenceEventAdapter {

    @Override
    public void afterInsert(PersistenceEvent event) throws Exception {
        DynamicVO vo = (DynamicVO) event.getVo();
        BigDecimal nunota = vo.asBigDecimal("NUNOTA");
        String tipoNeg = vo.asString("TIPONEG");

        if ("V".equals(tipoNeg)) {
            DynamicVO[] itens = (DynamicVO[]) JapeFactory.dao("ItemNota")
                .findByProperties(new String[]{"NUNOTA"}, new Object[]{nunota});
            BigDecimal totalDesconto = BigDecimal.ZERO;
            for (DynamicVO item : itens) {
                BigDecimal vlrUnit = item.asBigDecimal("VLRUNIT");
                BigDecimal qtd = item.asBigDecimal("QTDNEG");
                BigDecimal desconto = vlrUnit.multiply(qtd).multiply(new BigDecimal("0.10"));
                totalDesconto = totalDesconto.add(desconto);
                JapeFactory.dao("ItemNota").prepareToUpdateByPK(item.asBigDecimal("ID"))
                    .set("VLRDESCONTO", desconto).update();
            }
            JapeFactory.dao("Nota").prepareToUpdateByPK(nunota)
                .set("VLRTOTALDESCONTO", totalDesconto).update();
        }
    }
}
